SELECT COUNT(*) AS set_count
FROM sets
WHERE year = 2022;

SELECT name
FROM sets
WHERE year = 2022;

SELECT keyword
FROM set_keywords
WHERE set_num = '0';

SELECT COUNT(set_num) AS set_count
FROM set_keywords
WHERE keyword = 'town';

SELECT piece_count AS total_parts
FROM sets
WHERE set_num = '1';

SELECT set_num, piece_count
FROM sets
ORDER BY piece_count DESC;

SELECT COUNT(rating_id) AS rating_count
FROM set_ratings
WHERE set_num = '0';

SELECT AVG(rating) AS average_rating
FROM set_ratings
WHERE set_num = '1';

SELECT COUNT(*) AS total_comments
FROM set_comments
WHERE set_num = '0';

SELECT AVG(num_parts) AS average_parts
FROM sets
WHERE year = 1978;

SELECT set_num
FROM set_ratings
WHERE rating >= 4;

SELECT set_num, tag
FROM set_tags
WHERE tag = 'town';
